mapper.select:
SELECT aa.id, aa.staff_id, aa.apply_type, aa.start_datetime, aa.end_datetime, aa.reason, aa.audit_status, aa.auditor_id, aa.create_time, aa.approval_content,
si.name as staffName, si.images as staffImages,
di.dept_name, poi.name as positionName
FROM attendance_application aa left join staff_info si on (si.id = aa.staff_id) left join dept_info di on (di.id = si.dept_id) left join position_info poi on (poi.id = si.position_id) WHERE 1 = 1
AND si.name LIKE CONCAT('%',#{queryForm.staffName},'%')
AND aa.apply_type = #{queryForm.applyType}
AND aa.audit_status = #{queryForm.auditStatus}
AND si.user_id = #{queryForm.staffId}
order by aa.create_time desc
